:root {
            --navy: #004aad;
            --dark-navy: #061A3A;
            --cyan: #2fe8fa;
            --light-bg: #f8fafc;
        }

        /* ── Section 1: Hero ── */
        .team-hero {
            position: relative;
            height: 100vh;
            min-height: 600px;
            display: flex;
            align-items: center;
            overflow: hidden;
            text-align: left;
        }
        .team-hero-bg {
            position: absolute;
            inset: 0;
            background-image: url('../../assets/img/jo1.jpg');
            background-size: cover;
            background-position: center;
            background-attachment: fixed;
            transform: scale(1.05);
            transition: transform 10s ease-out;
            z-index: 0;
        }
        .team-hero.loaded .team-hero-bg {
            transform: scale(1);
        }
        .team-hero-overlay {
            position: absolute;
            inset: 0;
            background: rgba(6, 26, 58, 0.4);
            z-index: 1;
        }
        .team-hero-content {
            position: relative;
            z-index: 2;
            width: 100%;
            max-width: 1440px;
            margin: 0 auto;
            padding: 0 4rem;
            display: flex;
            flex-direction: column;
            align-items: flex-start;
        }
        .team-hero-title {
            font-size: clamp(3rem, 6vw, 4.5rem);
            font-weight: 700; /* 大氣、有力量，但不要過度厚重 */
            color: #ffffff;
            line-height: 1.2;
            margin-bottom: 2rem;
            letter-spacing: 0.08em;
            text-shadow: 0 4px 20px rgba(0,0,0,0.3);
            opacity: 0;
            transform: translateY(30px);
            animation: teamReveal 1s 0.3s ease forwards;
        }
        .team-hero-sub {
            font-size: clamp(1.1rem, 2vw, 1.4rem);
            color: rgba(255, 255, 255, 0.9);
            line-height: 1.8;
            font-weight: 400;
            letter-spacing: 0.05em;
            white-space: nowrap;
            opacity: 0;
            transform: translateY(20px);
            animation: teamReveal 1s 0.5s ease forwards;
        }

        /* Scroll hint */
        .team-scroll-hint {
            position: absolute;
            bottom: 2.5rem;
            left: 50%;
            transform: translateX(-50%);
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 8px;
            z-index: 3;
            opacity: 0;
            animation: teamReveal 1s 1.2s ease forwards;
        }
        .team-scroll-hint span {
            font-size: 0.7rem;
            letter-spacing: 0.15em;
            text-transform: uppercase;
            color: rgba(255,255,255,0.7);
        }
        .team-scroll-arrow {
            width: 22px; height: 22px;
            border-right: 2px solid rgba(255,255,255,0.6);
            border-bottom: 2px solid rgba(255,255,255,0.6);
            transform: rotate(45deg);
            animation: teamBounce 1.8s infinite;
        }

        @keyframes teamReveal { to { opacity: 1; transform: translateY(0); } }
        @keyframes teamBounce {
            0%,100% { transform: rotate(45deg) translateY(0); opacity: 0.4; }
            50% { transform: rotate(45deg) translateY(6px); opacity: 1; }
        }

        /* ── Section 2: Team Overview ── */
        .team-overview {
            padding: 8rem 0;
            background-image: url('../../assets/img/jo7.png');
            background-size: cover;
            background-position: center;
            background-attachment: fixed;
            text-align: center;
            position: relative;
            overflow: hidden;
        }
        .team-overview .team-overview-title,
        .team-overview-text p {
            color: #000000;
            text-shadow: none;
        }
        .team-overview::before,
        .team-overview::after {
            content: '';
            position: absolute;
            top: 50%;
            transform: translateY(-50%);
            width: 160px;
            height: 240px;
            background-image: radial-gradient(var(--cyan) 2px, transparent 2px);
            background-size: 24px 24px;
            opacity: 0.4;
            pointer-events: none;
        }
        .team-overview::before {
            left: 5%;
        }
        .team-overview::after {
            right: 5%;
        }
        .team-overview-inner {
            max-width: 800px;
            margin: 0 auto;
            padding: 0 2rem;
        }
        .team-overview-title {
            font-size: clamp(2rem, 4vw, 2.8rem);
            font-weight: 800;
            color: var(--dark-navy);
            margin-bottom: 2.5rem;
        }
        .team-overview-text p {
            font-size: 1.15rem;
            color: #4a5a7a;
            line-height: 2;
            margin-bottom: 1.8rem;
            text-align: justify;
            text-align-last: center;
        }
        .team-overview-text p:last-child {
            margin-bottom: 0;
        }

        /* ── Section 3: Core Advantages ── */
        .team-core {
            position: relative;
            padding: 8rem 0;
            min-height: 80vh;
            display: flex;
            align-items: center;
            overflow: hidden;
        }
        .team-core-bg {
            position: absolute;
            inset: 0;
            background-image: url('../../assets/img/bs18.jpg');
            background-size: cover;
            background-position: center;
            background-attachment: fixed;
            z-index: 0;
        }
        .team-core-overlay {
            position: absolute;
            inset: 0;
            background: rgba(6, 26, 58, 0.6);
            z-index: 1;
        }
        .team-core-inner {
            position: relative;
            z-index: 2;
            max-width: 1440px;
            margin: 0 auto;
            padding: 0 2rem;
            width: 100%;
        }
        .team-core-header {
            text-align: center;
            margin-bottom: 4rem;
        }
        .team-core-header h2 {
            font-size: clamp(2rem, 4vw, 2.8rem);
            font-weight: 800;
            color: #ffffff;
        }
        .team-core-grid {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 1.5rem;
        }
        .team-glass-card {
            background: rgba(255, 255, 255, 0.12);
            backdrop-filter: blur(16px);
            -webkit-backdrop-filter: blur(16px);
            border: 1px solid rgba(255, 255, 255, 0.2);
            border-radius: 20px;
            padding: 2.5rem 2rem;
            text-align: left;
            transition: transform 0.4s ease, box-shadow 0.4s ease, background 0.4s ease;
            display: flex;
            flex-direction: column;
        }
        .team-glass-card:hover {
            transform: translateY(-8px);
            background: rgba(255, 255, 255, 0.2);
            box-shadow: 0 20px 40px rgba(0,0,0,0.2);
            border-color: rgba(47,232,250, 0.4);
        }
        .team-glass-card h3 {
            font-size: 1.35rem;
            font-weight: 700;
            color: #ffffff;
            margin-bottom: 1rem;
            line-height: 1.4;
            min-height: 2.8em; /* Force equal title height to keep alignment */
        }
        .team-glass-card p {
            font-size: 1rem;
            color: rgba(255,255,255,0.9);
            line-height: 1.8;
            flex-grow: 1;
        }

        /* ── Section 4: Core Partners ── */
        .team-partners {
            position: relative;
            padding: 8rem 0;
            background: #000; /* Fallback */
            overflow: hidden;
        }
        .team-partners-bg {
            position: absolute;
            inset: 0;
            background-image: url('../../assets/img/jo2.jpg');
            background-size: cover;
            background-position: center;
            background-attachment: fixed;
            z-index: 0;
        }
        .team-partners-overlay {
            position: absolute;
            inset: 0;
            background: rgba(6, 26, 58, 0.7); /* Deep overlay for contrast */
            z-index: 1;
            display: none; /* Hide the dark mask per request */
        }
        .team-partners-inner {
            position: relative;
            z-index: 2;
            max-width: 1200px;
            margin: 0 auto;
            padding: 0 2rem;
        }
        .team-partners-header {
            text-align: center;
            margin-bottom: 5rem;
        }
        .team-partners-header h2 {
            font-size: clamp(2rem, 4vw, 2.8rem);
            font-weight: 800;
            color: #ffffff;
        }

        /* 2 + 2 + 1 Layout Grid System */
        .partner-row {
            display: flex;
            justify-content: center;
            gap: 2.5rem;
            margin-bottom: 2.5rem;
        }
        .partner-row:last-child {
            margin-bottom: 0;
        }

        .partner-card {
            flex: 1;
            min-width: 250px;
            max-width: 360px;
            background: rgba(255, 255, 255, 0.08); /* Semi-transparent background */
            backdrop-filter: blur(12px);
            -webkit-backdrop-filter: blur(12px);
            border: 1px solid rgba(255, 255, 255, 0.15);
            border-radius: 20px;
            overflow: hidden;
            display: flex;
            flex-direction: column;
            transition: all 0.4s ease;
            box-shadow: 0 10px 30px rgba(0,0,0,0.1);
        }

        .partner-card:hover {
            transform: translateY(-8px);
            background: rgba(255, 255, 255, 0.12);
            border-color: rgba(47,232,250, 0.5);
            box-shadow: 0 20px 40px rgba(0,0,0,0.3), 0 0 20px rgba(47,232,250,0.2); /* Micro-light on hover */
        }

        .partner-img-wrapper {
            width: 100%;
            aspect-ratio: 1/1;
            overflow: hidden;
            position: relative;
            background: rgba(255,255,255,0.05); /* Placeholder if img takes time */
        }

        .partner-img-wrapper img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            object-position: top;
            transition: transform 0.8s ease;
        }

        .partner-card:hover .partner-img-wrapper img {
            transform: scale(1.05);
        }

        .partner-info {
            padding: 2rem 2rem;
            display: flex;
            flex-direction: column;
            flex-grow: 1;
        }

        .partner-name {
            font-size: 1.4rem;
            font-weight: 800;
            color: #ffffff;
            margin-bottom: 0.2rem;
            letter-spacing: 0.05em;
        }

        .partner-title {
            font-size: 0.95rem;
            font-weight: 600;
            color: var(--cyan);
            margin-bottom: 1.25rem;
            letter-spacing: 0.05em;
        }

        .partner-desc {
            font-size: 0.95rem;
            color: rgba(255,255,255,0.85);
            line-height: 1.7;
        }

        /* ── Responsive ── */
        @media (max-width: 1024px) {
            .team-core-grid {
                grid-template-columns: repeat(2, 1fr);
            }
            .team-glass-card h3 {
                min-height: auto;
            }
        }
        @media (max-width: 768px) {
            .team-hero-content {
                padding: 0 2rem;
            }
            .partner-row {
                flex-direction: column;
                align-items: center;
                gap: 2.5rem;
            }
            .partner-card {
                max-width: 100%;
            }
            .team-hero-sub {
                white-space: normal;
                max-width: 100%;
            }
            .team-overview-text p {
                text-align: left;
                text-align-last: left;
            }
        }
        @media (max-width: 600px) {
            .team-core-grid {
                grid-template-columns: 1fr;
            }
            .team-hero-title {
                font-size: 2.5rem;
            }
        }

document.addEventListener('DOMContentLoaded', () => {
            // Scroll fade-up animations
            const observer = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('visible');
                    }
                });
            }, { threshold: 0.1 });

            document.querySelectorAll('.fade-up').forEach((el, index) => {
                if (el.classList.contains('delay-1')) el.style.transitionDelay = '0.15s';
                if (el.classList.contains('delay-2')) el.style.transitionDelay = '0.3s';
                observer.observe(el);
            });

            // 年份 Filter 邏輯 (UI demo)
            const filterBtns = document.querySelectorAll('.filter-btn');
            filterBtns.forEach(btn => {
                btn.addEventListener('click', (e) => {
                    filterBtns.forEach(b => b.classList.remove('active'));
                    e.target.classList.add('active');

                    const year = e.target.getAttribute('data-year');
                    // 這裡可加入過濾新聞卡片的邏輯
                    const cards = document.querySelectorAll('.news-card');
                    cards.forEach(card => {
                        const dateText = card.querySelector('.card-date').innerText;
                        const cardYear = dateText.split('/')[0];
                        if (year === 'all' || cardYear === year) {
                            card.style.display = 'flex';
                            setTimeout(() => { card.style.opacity = '1'; }, 50);
                        } else {
                            card.style.opacity = '0';
                            setTimeout(() => { card.style.display = 'none'; }, 300);
                        }
                    });
                });
            });
        });

:root {
            --brand-blue: #004AAD;
            --brand-cyan: #2FE8FA;
            --dark-overlay: rgba(0, 0, 0, 0.45); /* Dark overlay with high transparency */
        }

        /* ── Hero Section ── */
        .news-hero {
            position: relative;
            height: 60vh;
            min-height: 500px;
            display: flex;
            align-items: center;
            justify-content: center;
            text-align: center;
            overflow: hidden;
        }
        .news-hero-bg {
            position: absolute;
            inset: 0;
            background-image: url('../../image/semi1.png');
            background-size: cover;
            background-position: center;
            background-attachment: fixed;
            z-index: 0;
        }
        .news-hero-overlay {
            position: absolute;
            inset: 0;
            background: var(--dark-overlay);
            z-index: 1;
        }
        .news-hero-content {
            position: relative;
            z-index: 2;
            padding: 0 2rem;
            animation: fadeUp 1s ease forwards;
        }
        .news-hero-content h1 {
            font-size: clamp(2.5rem, 5vw, 4rem);
            font-weight: 800;
            color: #ffffff;
            margin-bottom: 1rem;
            letter-spacing: 0.05em;
            text-shadow: 0 4px 15px rgba(0,0,0,0.3);
        }
        .news-hero-content p {
            font-size: clamp(1.1rem, 2vw, 1.4rem);
            color: rgba(255, 255, 255, 0.95);
            font-weight: 400;
        }

        /* ── Filter Section ── */
        .news-filter-container {
            max-width: 1200px;
            margin: -30px auto 3rem;
            position: relative;
            z-index: 10;
            display: flex;
            justify-content: center;
        }
        .news-filter {
            background: #ffffff;
            box-shadow: 0 10px 30px rgba(0, 74, 173, 0.1);
            border-radius: 50px;
            padding: 0.5rem 1rem;
            display: inline-flex;
            gap: 0.5rem;
        }
        .filter-btn {
            border: none;
            background: transparent;
            padding: 0.6rem 1.5rem;
            font-size: 0.95rem;
            font-weight: 600;
            color: #555;
            border-radius: 30px;
            cursor: pointer;
            transition: all 0.3s ease;
        }
        .filter-btn:hover {
            color: var(--brand-blue);
            background: rgba(0, 74, 173, 0.05);
        }
        .filter-btn.active {
            background: var(--brand-blue);
            color: #ffffff;
            box-shadow: 0 4px 15px rgba(0, 74, 173, 0.3);
        }

        /* ── News Cards Section ── */
        .news-section {
            padding: 2rem 2rem 8rem;
            background-color: #f8fbff;
        }
        .news-grid {
            max-width: 1200px;
            margin: 0 auto;
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 3rem;
        }

        /* 單張卡片設計 */
        .news-card {
            background: #ffffff;
            border-radius: 20px;
            overflow: hidden;
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.04);
            display: flex;
            flex-direction: column;
            text-decoration: none;
            transition: all 0.4s cubic-bezier(0.165, 0.84, 0.44, 1);
            border: 1px solid rgba(0, 74, 173, 0.05);
        }
        .news-card:hover {
            transform: translateY(-10px);
            box-shadow: 0 20px 40px rgba(0, 74, 173, 0.12), 0 0 20px rgba(47, 232, 250, 0.15);
            border-color: rgba(47, 232, 250, 0.3);
        }

        /* 卡片上半部 圖片 */
        .card-img-wrap {
            width: 100%;
            aspect-ratio: 16/10;
            overflow: hidden;
            position: relative;
        }
        .card-img-wrap img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            transition: transform 0.6s ease;
        }
        .news-card:hover .card-img-wrap img {
            transform: scale(1.05);
        }

        /* 卡片下半部 內容 */
        .card-content {
            padding: 2.5rem 2rem;
            display: flex;
            flex-direction: column;
            flex-grow: 1;
        }

        .card-meta {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-bottom: 1.2rem;
        }

        .card-date {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--brand-blue);
            display: flex;
            align-items: center;
        }
        .card-date::before {
            content: '';
            display: inline-block;
            width: 8px;
            height: 8px;
            background-color: var(--brand-blue);
            border-radius: 50%;
            margin-right: 8px;
        }

        .card-source {
            font-size: 0.8rem;
            font-weight: 500;
            color: #8899a6;
            letter-spacing: 0.05em;
            text-transform: uppercase;
        }

        .card-title {
            font-size: 1.4rem;
            font-weight: 700;
            color: #1a1a2e;
            line-height: 1.5;
            margin-bottom: 2rem;
            /* 強制最多兩行 */
            display: -webkit-box;
            -webkit-line-clamp: 2;
            -webkit-box-orient: vertical;
            overflow: hidden;
            transition: color 0.3s ease;
        }
        .news-card:hover .card-title {
            color: var(--brand-blue);
        }

        .card-cta {
            margin-top: auto;
            color: var(--brand-blue);
            font-size: 1rem;
            font-weight: 700;
            display: inline-flex;
            align-items: center;
            position: relative;
            width: fit-content;
        }
        .card-cta span {
            margin-left: 0.5rem;
            transition: transform 0.3s ease;
        }
        .news-card:hover .card-cta span {
            transform: translateX(5px);
        }
        /* 亮起底線動畫 */
        .card-cta::after {
            content: '';
            position: absolute;
            bottom: -4px;
            left: 0;
            width: 0;
            height: 2px;
            background-color: var(--brand-cyan);
            transition: width 0.3s ease;
        }
        .news-card:hover .card-cta::after {
            width: 100%;
        }

        /* ── Bottom Section (延伸閱讀) ── */
        .bottom-nav-section {
            padding: 8rem 2rem;
            background-color: #ffffff;
            position: relative;
        }
        .bottom-nav-title {
            text-align: center;
            font-size: 2.2rem;
            font-weight: 800;
            color: #1a1a2e;
            margin-bottom: 4rem;
        }
        .bottom-nav-grid {
            max-width: 1200px;
            margin: 0 auto;
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 2rem;
        }

        .nav-card {
            position: relative;
            border-radius: 20px;
            overflow: hidden;
            aspect-ratio: 4/3;
            text-decoration: none;
            box-shadow: 0 4px 15px rgba(0,0,0,0.05);
            transition: transform 0.4s ease, box-shadow 0.4s ease;
        }
        .nav-card:hover {
            transform: translateY(-8px);
            box-shadow: 0 15px 35px rgba(0, 74, 173, 0.15);
        }

        .nav-card-bg {
            position: absolute;
            inset: 0;
            background-size: cover;
            background-position: center;
            transition: transform 0.8s ease;
        }
        .nav-card:hover .nav-card-bg {
            transform: scale(1.08);
        }

        .nav-card-overlay {
            position: absolute;
            inset: 0;
            background: linear-gradient(to top, rgba(0, 74, 173, 0.8) 0%, rgba(0, 74, 173, 0.2) 100%);
            display: flex;
            align-items: flex-end;
            padding: 2rem;
        }

        .nav-card-title {
            color: #ffffff;
            font-size: 1.5rem;
            font-weight: 700;
            letter-spacing: 0.1em;
            display: flex;
            align-items: center;
            width: 100%;
            justify-content: space-between;
        }
        .nav-card-title i {
            opacity: 0;
            transform: translateX(-10px);
            color: var(--brand-cyan);
            transition: all 0.3s ease;
        }
        .nav-card:hover .nav-card-title i {
            opacity: 1;
            transform: translateX(0);
        }

        /* ── Awards Section ── */
