            max-width: 1200px;
            margin: 0 auto;
            position: relative;
            z-index: 1;
        }
        .awards-header {
            text-align: center;
            margin-bottom: 4rem;
        }
        .awards-header h2 {
            font-size: clamp(2rem, 4vw, 2.8rem);
            font-weight: 800;
            color: #ffffff;
            margin-bottom: 1rem;
            letter-spacing: 0.05em;
        }
        .awards-header p {
            font-size: 1.1rem;
            color: rgba(255, 255, 255, 0.8);
            font-weight: 400;
            margin: 0;
        }
        .awards-grid {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 3rem;
        }
        .award-card {
            background: rgba(20, 30, 50, 0.6);
            border: 1px solid rgba(47, 232, 250, 0.15);
            border-radius: 20px;
            overflow: hidden;
            backdrop-filter: blur(10px);
            transition: all 0.4s cubic-bezier(0.165, 0.84, 0.44, 1);
            display: flex;
            flex-direction: column;
        }
        .award-card:hover {
            transform: translateY(-8px);
            border-color: rgba(47, 232, 250, 0.6);
            box-shadow: 0 15px 35px rgba(0, 0, 0, 0.4), 0 0 20px rgba(47, 232, 250, 0.15);
        }
        .award-img-wrap {
            width: 100%;
            aspect-ratio: 16/9;
            overflow: hidden;
            position: relative;
            background: #111;
        }
        .award-img-wrap img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            opacity: 0.85;
            transition: transform 0.6s ease, opacity 0.4s ease;
        }
        .award-card:hover .award-img-wrap img {
            transform: scale(1.05);
            opacity: 1;
        }
        .award-content {
            padding: 2.5rem;
            flex-grow: 1;
            display: flex;
            flex-direction: column;
        }
        .award-year {
            font-size: 0.95rem;
            font-weight: 600;
